theme.custom_css_code:
.twentyone-wrap{
  width:100%;
  background:transparent;
  font-family:Arial,sans-serif;
  color:#ffffff;
}
.twentyone-card{
  background:#1c1d20;
  border:1px solid rgba(255,255,255,0.12);
  border-radius:20px;
  padding:22px;
  box-sizing:border-box;
  box-shadow:0 10px 30px rgba(0,0,0,0.28);
}
.twentyone-title{
  margin:0 0 18px;
  font-size:22px;
  line-height:1.2;
  font-weight:700;
  color:#ffffff;
}
.twentyone-subtitle{
  margin:0 0 14px;
  font-size:16px;
  line-height:1.3;
  font-weight:700;
  color:#ffffff;
}
.twentyone-table-wrap{
  width:100%;
  overflow-x:auto;
}
.twentyone-table{
  width:100%;
  min-width:640px;
  border-collapse:collapse;
  color:#ffffff;
}
.twentyone-table tr{
  border-bottom:1px solid rgba(255,255,255,0.1);
}
.twentyone-table tr:last-child{
  border-bottom:none;
}
.twentyone-table td{
  padding:14px 12px;
  vertical-align:top;
  font-size:14px;
  line-height:1.45;
}
.twentyone-table td:first-child{
  width:38%;
  color:rgba(255,255,255,0.72);
  font-weight:700;
}
.twentyone-chart-block{
  display:flex;
  flex-direction:column;
  gap:14px;
}
.twentyone-row{
  display:grid;
  grid-template-columns:150px 1fr 56px;
  gap:14px;
  align-items:center;
}
.twentyone-label{
  font-size:14px;
  line-height:1.3;
  color:#ffffff;
  font-weight:700;
}
.twentyone-bar{
  position:relative;
  width:100%;
  height:18px;
  background:rgba(255,255,255,0.08);
  border-radius:999px;
  overflow:hidden;
}
.twentyone-fill{
  position:absolute;
  left:0;
  top:0;
  bottom:0;
  border-radius:999px;
}
.twentyone-fill--gold{
  background:linear-gradient(90deg,#f6c453 0%,#ffdf87 100%);
}
.twentyone-fill--blue{
  background:linear-gradient(90deg,#4ea1ff 0%,#7fc1ff 100%);
}
.twentyone-fill--green{
  background:linear-gradient(90deg,#32d296 0%,#7cf0c6 100%);
}
.twentyone-fill--violet{
  background:linear-gradient(90deg,#9b7bff 0%,#c0a8ff 100%);
}
.twentyone-fill--red{
  background:linear-gradient(90deg,#ff6b6b 0%,#ff9c9c 100%);
}
.twentyone-fill--silver{
  background:linear-gradient(90deg,#7d8494 0%,#a5adbe 100%);
}
.twentyone-value{
  text-align:right;
  font-size:14px;
  line-height:1.2;
  color:#ffffff;
  font-weight:700;
}
.twentyone-grid-2{
  display:grid;
  grid-template-columns:1fr 1fr;
  gap:18px;
}
.twentyone-radar{
  position:relative;
  width:100%;
  max-width:420px;
  aspect-ratio:1/1;
  margin:0 auto;
}
.twentyone-radar svg{
  width:100%;
  height:100%;
  display:block;
}
.twentyone-legend{
  display:grid;
  grid-template-columns:1fr;
  gap:10px;
}
.twentyone-legend-item{
  display:flex;
  align-items:center;
  gap:10px;
  font-size:14px;
  line-height:1.4;
  color:#ffffff;
}
.twentyone-dot{
  width:12px;
  height:12px;
  border-radius:50%;
  flex:0 0 12px;
}
.twentyone-dot--brand{
  background:#f6c453;
}
.twentyone-dot--market{
  background:#7d8494;
}
.twentyone-note{
  margin:2px 0 0;
  font-size:13px;
  line-height:1.5;
  color:rgba(255,255,255,0.72);
}
@media (max-width:767px){
  .twentyone-card{
    padding:16px;
    border-radius:16px;
  }
  .twentyone-title{
    font-size:19px;
  }
  .twentyone-row{
    grid-template-columns:1fr;
    gap:8px;
  }
  .twentyone-value{
    text-align:left;
  }
  .twentyone-grid-2{
    grid-template-columns:1fr;
  }
}
